import{c as a,Q as t,j as e,m as i}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Prompt Caching 核心教訓 — Thariq Shihipar（Claude Code 團隊）","description":"","frontmatter":{"title":"Prompt Caching 核心教訓 — Thariq Shihipar（Claude Code 團隊）","source":"https://claude.com/blog/lessons-from-building-claude-code-prompt-caching-is-everything","type":"best-practices"},"headers":[],"relativePath":"research/best-practices/28-thariq-prompt-caching-lessons.md","filePath":"research/best-practices/28-thariq-prompt-caching-lessons.md","lastUpdated":1779894392000}'),n={name:"research/best-practices/28-thariq-prompt-caching-lessons.md"};function o(p,s,l,r,h,c){return t(),e("div",null,[...s[0]||(s[0]=[i(`<h1 id="prompt-caching-核心教訓-—-thariq-shihipar-claude-code-團隊" tabindex="-1">Prompt Caching 核心教訓 — Thariq Shihipar（Claude Code 團隊） <a class="header-anchor" href="#prompt-caching-核心教訓-—-thariq-shihipar-claude-code-團隊" aria-label="Permalink to &quot;Prompt Caching 核心教訓 — Thariq Shihipar（Claude Code 團隊）&quot;">​</a></h1><blockquote><p>來源：<a href="https://claude.com/blog/lessons-from-building-claude-code-prompt-caching-is-everything" target="_blank" rel="noreferrer">https://claude.com/blog/lessons-from-building-claude-code-prompt-caching-is-everything</a><br> 作者：Thariq Shihipar（MTS, Claude Code Team）<br> 收錄日期：2026-05-16<br> 重要性：★★★（直接影響 Claude Code 架構設計與 Session 管理）</p></blockquote><hr><h2 id="核心主張" tabindex="-1">核心主張 <a class="header-anchor" href="#核心主張" aria-label="Permalink to &quot;核心主張&quot;">​</a></h2><p>「Cache rules everything」——長跑型 Agentic 產品應將 <strong>Cache Hit Rate 視為關鍵指標</strong>，下降時觸發 incident 處理。這不是優化項，是生產系統的基本健康指標。</p><hr><h2 id="一、前綴匹配是快取的根本" tabindex="-1">一、前綴匹配是快取的根本 <a class="header-anchor" href="#一、前綴匹配是快取的根本" aria-label="Permalink to &quot;一、前綴匹配是快取的根本&quot;">​</a></h2><p>Prompt Caching 的工作方式：<strong>逐 token 從頭比對前綴</strong>，遇到第一個不同 token 即停止快取。</p><p><strong>最有效的分層結構（靜態 → 動態）</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. System prompt + Tools       ← 最穩定，全域快取</span></span>
<span class="line"><span>2. 專案特定檔案 / CLAUDE.md   ← 中度穩定，跨 session 快取</span></span>
<span class="line"><span>3. Session context             ← 僅當次 session</span></span>
<span class="line"><span>4. 對話訊息（最新輪次）        ← 每次請求不同</span></span></code></pre></div><p>越靠前的內容變動越少，快取效益越高。</p><hr><h2 id="二、用-messages-代替更新-system-prompt" tabindex="-1">二、用 Messages 代替更新 System Prompt <a class="header-anchor" href="#二、用-messages-代替更新-system-prompt" aria-label="Permalink to &quot;二、用 Messages 代替更新 System Prompt&quot;">​</a></h2><p><strong>錯誤做法</strong>：有新資訊（時間戳、檔案變更）時修改 system prompt → 無效化整個快取前綴。</p><p><strong>正確做法</strong>：透過後續對話訊息傳遞更新資訊，使用 <code>&lt;system-reminder&gt;</code> 標籤標示動態注入內容：</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">&lt;!-- 在後續訊息中注入，不修改 system prompt --&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">system-reminder</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  現在時間：2026-05-16 10:30</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  最近修改的檔案：src/main.py</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">system-reminder</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><hr><h2 id="三、mid-session-禁止切換模型" tabindex="-1">三、Mid-Session 禁止切換模型 <a class="header-anchor" href="#三、mid-session-禁止切換模型" aria-label="Permalink to &quot;三、Mid-Session 禁止切換模型&quot;">​</a></h2><p>Prompt Cache <strong>是模型專屬的</strong>。從 Opus 切換到 Haiku（或反之）：</p><ul><li>快取前綴全部失效</li><li>下一輪請求必須重建整個快取（等同從頭支付計算費用）</li></ul><p><strong>正確做法</strong>：需要用不同模型 → 用 <strong>Subagent</strong>（每個 subagent 有獨立 context + 快取）。</p><hr><h2 id="四、工具管理-對話中不增刪工具" tabindex="-1">四、工具管理：對話中不增刪工具 <a class="header-anchor" href="#四、工具管理-對話中不增刪工具" aria-label="Permalink to &quot;四、工具管理：對話中不增刪工具&quot;">​</a></h2><p>工具定義（tool definitions）是快取前綴的一部分。增刪工具 = 前綴變動 = 快取失效。</p><p><strong>應對策略</strong>：</p><ul><li>保留所有工具定義在前綴中（不需要的用 stub 佔位）</li><li>用輕量 stub + <code>defer_loading: true</code> 保持前綴穩定，同時支援按需載入：</li></ul><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;heavy_tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;description&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;...&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;defer_loading&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>EnterPlanMode 等行為控制工具也用此模式——工具定義永遠在，用工具本身的呼叫來控制模式。</p><hr><h2 id="五、compaction-不能破壞快取前綴" tabindex="-1">五、Compaction 不能破壞快取前綴 <a class="header-anchor" href="#五、compaction-不能破壞快取前綴" aria-label="Permalink to &quot;五、Compaction 不能破壞快取前綴&quot;">​</a></h2><p>Context window 滿了進行 Compact 時：</p><p><strong>錯誤做法</strong>：用不同的 system prompt 或 tools 建立 compaction 請求 → 後續 session 失去快取匹配。</p><p><strong>正確做法</strong>：Compact 請求必須使用<strong>與父對話完全相同的</strong> system prompt + tools + user context，確保前綴匹配：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>compaction_request = {</span></span>
<span class="line"><span>    &quot;system&quot;: original_system_prompt,  # 完全相同</span></span>
<span class="line"><span>    &quot;tools&quot;: original_tools,           # 完全相同</span></span>
<span class="line"><span>    &quot;messages&quot;: [</span></span>
<span class="line"><span>        {&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: f&quot;請摘要以下對話：{conversation_history}&quot;}</span></span>
<span class="line"><span>    ]</span></span>
<span class="line"><span>}</span></span></code></pre></div><hr><h2 id="六、監控快取命中率" tabindex="-1">六、監控快取命中率 <a class="header-anchor" href="#六、監控快取命中率" aria-label="Permalink to &quot;六、監控快取命中率&quot;">​</a></h2><p>將 Cache Hit Rate 加入核心監控指標，等同 uptime 指標：</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cache_hit_rate </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> response.usage.cache_read_input_tokens </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> response.usage.input_tokens</span></span></code></pre></div><p>Claude Code 內部實踐：</p><ul><li>Cache hit rate 下降 → 觸發 incident 流程</li><li>找出導致快取失效的變更（通常是 system prompt 動態注入、工具增刪、模型切換）</li></ul><hr><h2 id="快速-checklist" tabindex="-1">快速 Checklist <a class="header-anchor" href="#快速-checklist" aria-label="Permalink to &quot;快速 Checklist&quot;">​</a></h2><ul><li>[ ] System prompt 結構：靜態內容放最前，動態資訊用 messages 傳遞</li><li>[ ] Session 內不切換模型（需換模型 → 開 subagent）</li><li>[ ] 工具定義對話中不增刪（用 stub + defer_loading）</li><li>[ ] Compact 操作保留原始 system prompt + tools</li><li>[ ] Cache hit rate 加入 observability dashboard</li></ul><hr><h2 id="與現有-workspace-規則的對應" tabindex="-1">與現有 workspace 規則的對應 <a class="header-anchor" href="#與現有-workspace-規則的對應" aria-label="Permalink to &quot;與現有 workspace 規則的對應&quot;">​</a></h2><p>本文主張與 workspace 已有規則高度一致，並補充細節：</p><table tabindex="0"><thead><tr><th>本文新增細節</th><th>對應現有規則</th></tr></thead><tbody><tr><td><code>&lt;system-reminder&gt;</code> 注入動態資訊</td><td><code>context-management.md</code> § Prompt Caching 核心原則</td></tr><tr><td>工具 stub + defer_loading</td><td><code>best-practices/08-prompt-caching.md</code></td></tr><tr><td>Compact 保留相同 system prompt</td><td><code>context-management.md</code> § Compact hint 格式</td></tr><tr><td>Mid-session 禁止切換模型</td><td><code>context-management.md</code> § 禁止 mid-session</td></tr></tbody></table><blockquote><p>一手來源（O 層）：claude.com blog，作者為 Thariq Shihipar（Claude Code MTS）</p></blockquote>`,48)])])}const k=a(n,[["render",o]]);export{g as __pageData,k as default};
